### 3.1 Backend Endpoint

**New endpoint:** `POST /api/rooms/:pin/ai-chat`

```javascript
// server.js — new endpoint
app.post('/api/rooms/:pin/ai-chat', async (req, res) => {
  const { message, conversationHistory, userId, role } = req.body;
  if (!message) return res.status(400).json({ error: 'Message required' });

  const rooms = readJSON('rooms.json');
  const room = rooms[req.params.pin];
  if (!room) return res.status(404).json({ error: 'Room not found' });

  // Gather session context
  const chars = readJSON('characters.json');
  const roomChars = Object.values(chars).filter(c => c.roomPin === req.params.pin);
  const context = buildSessionContext(room, roomChars);

  // Build conversation for AI
  const systemPrompt = buildAISystemPrompt(context, role);

  const recentHistory = (conversationHistory || []).slice(-20).map(m => 
    `${m.role === 'user' ? 'User' : 'AI'}: ${m.text}`
  ).join('\n');

  const aiPrompt = `${systemPrompt}\n\nConversation so far:\n${recentHistory}\n\nUser: ${message}\n\nRespond helpfully. Keep answers concise (under 300 words unless detailed rules explanation needed). Use markdown formatting.`;

  try {
    const response = await fetch('http://127.0.0.1:3001/voice/chat', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ agentId: 'sarael', message: aiPrompt })
    });
    const data = await response.json();
    const reply = data.response || data.message || 'The oracle is silent...';

    // Save to room's AI chat history
    if (!room.aiChatHistory) room.aiChatHistory = [];
    room.aiChatHistory.push(
      { role: 'user', text: message, userId, timestamp: Date.now() },
      { role: 'ai', text: reply, timestamp: Date.now() }
    );
    // Keep last 100 messages
    if (room.aiChatHistory.length > 100) {
      room.aiChatHistory = room.aiChatHistory.slice(-100);
    }
    rooms[req.params.pin] = room;
    writeJSON('rooms.json', rooms);

    res.json({ reply, context: { partySize: roomChars.length, combatActive: room.initiative?.active || false } });
  } catch (err) {
    res.status(500).json({ error: 'AI service unavailable: ' + err.message });
  }
});

// Get AI chat history for a room
app.get('/api/rooms/:pin/ai-chat', (req, res) => {
  const rooms = readJSON('rooms.json');
  const room = rooms[req.params.pin];
  if (!room) return res.status(404).json({ error: 'Room not found' });
  res.json(room.aiChatHistory || []);
});
```

