function rollDie(sides) {
  return Math.floor(Math.random() * sides) + 1;
}

function rollDice(notation, mode = 'normal') {
  const parsed = parseDice(notation);
  if (!parsed) return null;

  let results = [];
  let total = 0;
  let detail = '';
  let droppedIndex = -1;
  let keptIndex = -1;

  if (mode !== 'normal' && parsed.sides === 20 && parsed.count === 1) {
    const r1 = rollDie(20);
    const r2 = rollDie(20);
    const chosen = mode === 'advantage' ? Math.max(r1, r2) : Math.min(r1, r2);
    results = [r1, r2];
    total = chosen + parsed.modifier;
    const kept = mode === 'advantage' ? 'highest' : 'lowest';
    keptIndex = mode === 'advantage' ? (r1 >= r2 ? 0 : 1) : (r1 <= r2 ? 0 : 1);
    detail = `[${r1}, ${r2}] \u2192 ${kept}: ${chosen}`;
    if (parsed.modifier) detail += ` ${parsed.modifier >= 0 ? '+' : ''}${parsed.modifier}`;
  } else {
    for (let i = 0; i < parsed.count; i++) {
      results.push(rollDie(parsed.sides));
    }
    const sum = results.reduce((a, b) => a + b, 0);
    total = sum + parsed.modifier;
    detail = results.length > 1 ? `[${results.join(', ')}] = ${sum}` : `[${results[0]}]`;
    if (parsed.modifier) detail += ` ${parsed.modifier >= 0 ? '+' : ''}${parsed.modifier}`;
  }

  return { notation, results, total, detail, mode, sides: parsed.sides, count: parsed.count, modifier: parsed.modifier, droppedIndex, keptIndex };
}

function rollDropLowest() {
  const results = [rollDie(6), rollDie(6), rollDie(6), rollDie(6)];
  const minVal = Math.min(...results);
  const droppedIndex = results.indexOf(minVal);
  const kept = results.filter((_, i) => i !== droppedIndex);
  const sum = kept.reduce((a, b) => a + b, 0);
  const detail = `[${results.map((r, i) => i === droppedIndex ? '\u0336' + r + '\u0336' : r).join(', ')}] \u2192 ${sum}`;
  return {
    notation: '4d6kh3',
    results,
    total: sum,
    detail,
    mode: 'drop-lowest',
    sides: 6,
    count: 4,
    modifier: 0,
    droppedIndex,
    keptIndex: -1
  };
}

function performRoll(notation, mode, extraModifier) {
  extraModifier = extraModifier || 0;
  let result;

  if (notation === '4d6kh3') {
    result = rollDropLowest();
  } else if (notation === 'adv') {
    result = rollDice('1d20', 'advantage');
    if (result) result.notation = '1d20 (adv)';
  } else if (notation === 'dis') {
    result = rollDice('1d20', 'disadvantage');
    if (result) result.notation = '1d20 (dis)';
  } else {
    result = rollDice(notation, mode);
  }

  if (!result) return;

  if (extraModifier && notation !== '4d6kh3') {
    result.total += extraModifier;
    result.modifier = (result.modifier || 0) + extraModifier;
    const sign = extraModifier >= 0 ? '+' : '';
    result.detail += ` ${sign}${extraModifier}(mod)`;
  }

  DiceSound.play();
  showTrayAnimation(result);

  sendWS({
    type: 'dice-roll',
    notation: result.notation,
    results: result.results,
    total: result.total,
    detail: result.detail,
    mode: result.mode,
    sides: result.sides
  });
}

function getDieClass(sides) {
  return 'die-d' + sides;
}

function showTrayAnimation(result) {
  const trayDice = $('#dice-tray-dice');
  const trayResult = $('#dice-tray-result');
  hide(trayResult);
  trayDice.innerHTML = '';

  const sides = result.sides || 20;
  const animDuration = 1200;

  result.results.forEach((val, idx) => {
    const die = document.createElement('div');
    die.className = 'tray-die ' + getDieClass(sides) + ' rolling';
    die.textContent = '?';
    die.style.animationDelay = (idx * 100) + 'ms';
    trayDice.appendChild(die);

    let scrambleInterval = setInterval(() => {
      die.textContent = Math.floor(Math.random() * sides) + 1;
    }, 80);

    setTimeout(() => {
      clearInterval(scrambleInterval);
      die.classList.remove('rolling');
      die.classList.add('landed');
      die.textContent = val;

      if ((result.mode === 'advantage' || result.mode === 'disadvantage') && result.results.length === 2) {
        if (idx === result.keptIndex) {
          die.classList.add('adv-kept');
        } else {
          die.classList.add('adv-dropped');
        }
      }

      if (result.mode === 'drop-lowest' && idx === result.droppedIndex) {
        die.classList.add('dropped');
      }
    }, animDuration + idx * 100);
  });

  const totalDelay = animDuration + (result.results.length - 1) * 100 + 200;
  setTimeout(() => {
    show(trayResult);
    const totalEl = $('#result-total');
    const detailEl = $('#result-detail');
    const specialEl = $('#result-special');

    totalEl.textContent = result.total;
    totalEl.className = 'result-total';
