        totalEl.classList.add('crit-fail');
        specialEl.textContent = '\uD83D\uDC80 FUMBLE! \uD83D\uDC80';
        specialEl.className = 'result-special fumble';
        show(specialEl);
      }
    }

    if ((result.mode === 'advantage' || result.mode === 'disadvantage') && sides === 20) {
      const keptVal = result.results[result.keptIndex];
      if (keptVal === 20) {
        totalEl.classList.add('crit-success');
        specialEl.textContent = '\u2694\uFE0F CRITICAL! \u2694\uFE0F';
        specialEl.className = 'result-special critical';
        show(specialEl);
      } else if (keptVal === 1) {
        totalEl.classList.add('crit-fail');
        specialEl.textContent = '\uD83D\uDC80 FUMBLE! \uD83D\uDC80';
        specialEl.className = 'result-special fumble';
        show(specialEl);
      }
    }
  }, totalDelay);
}

